// Copyright Transpersonal Game Studio. All Rights Reserved.\n\n#pragma once\n\n#include \"CoreMinimal.h\"\n#include \"GameFramework/Actor.h\"\n#include \"Components/ActorComponent.h\"\n#include \"PCGComponent.h\"\n#include \"PCGGraph.h\"\n#include \"PCGData.h\"\n#include \"PCGSettings.h\"\n#include \"Engine/World.h\"\n#include \"Landscape.h\"\n#include \"LandscapeProxy.h\"\n#include \"WorldPartition/WorldPartition.h\"\n#include \"WorldPartition/DataLayer/DataLayer.h\"\n#include \"Engine/DataTable.h\"\n#include \"Math/UnrealMathUtility.h\"\n#include \"Performance/PerformanceTargets.h\"\n#include \"JurassicWorldGeneratorV3.generated.h\"\n\nclass UPCGGraph;\nclass UPCGComponent;\nclass ALandscape;\nclass ULandscapeComponent;\nclass UDataLayer;\nclass UPerformanceMonitor;\n\n/**\n * @brief Advanced Jurassic World Generator V3 - Performance Optimized\n * \n * Creates the prehistoric survival world from the game concept:\n * - Regional scale: ~200km² explorable terrain (8129x8129 landscape)\n * - 5 distinct biomes: Forest (spawn), Swamp, Savana, Desert, Snowy Rockside\n * - Impassable mountain borders creating natural boundaries\n * - Dynamic river system flowing from mountains to center\n * - Performance-first design: 60fps PC / 30fps console target\n * - World Partition integration with hierarchical PCG generation\n * \n * Design Philosophy (Agent #5):\n * \"A natureza não é aleatória — tem padrões, tem lógica, tem história escrita na terra.\n * Um mundo que funciona como sistema gera histórias que nenhum designer conseguiu planear.\n * Cada vale tem uma razão. Cada rio determinou onde uma cidade cresceu.\"\n * \n * @author Procedural World Generator — Agent #5\n * @version 3.0 — March 2026\n */\n\n/** Enhanced biome types following the Geographic Guide */\nUENUM(BlueprintType)\nenum class EJurassicBiomeV3 : uint8\n{\n    Forest          UMETA(DisplayName = \"Forest (Tropical Forest) - Player Spawn\"),\n    Swamp           UMETA(DisplayName = \"Swamp - Dense Vegetation\"),\n    Savana          UMETA(DisplayName = \"Savana - Open Grasslands\"),\n    Desert          UMETA(DisplayName = \"Desert - Arid Wasteland\"),\n    SnowyRockside   UMETA(DisplayName = \"Snowy Rockside - Cold Mountains\"),\n    MountainBorder  UMETA(DisplayName = \"Mountain Border (Impassable)\"),\n    RiverPlains     UMETA(DisplayName = \"River Plains - Fertile Valleys\"),\n    Transition      UMETA(DisplayName = \"Transition Zone - Biome Blending\")\n};\n\n/** Geological formation types for realistic terrain */\nUENUM(BlueprintType)\nenum class EGeologicalFormationV3 : uint8\n{\n    Sedimentary     UMETA(DisplayName = \"Sedimentary - River Deposits\"),\n    Volcanic        UMETA(DisplayName = \"Volcanic - Ancient Eruptions\"),\n    Metamorphic     UMETA(DisplayName = \"Metamorphic - Mountain Cores\"),\n    Erosional       UMETA(DisplayName = \"Erosional - Wind/Water Carved\"),\n    Glacial         UMETA(DisplayName = \"Glacial - Ice Age Remnants\")\n};\n\n/** Water system types for ecosystem simulation */\nUENUM(BlueprintType)\nenum class EWaterSystemType : uint8\n{\n    MainRiver       UMETA(DisplayName = \"Main River - Major Water Source\"),\n    Tributary       UMETA(DisplayName = \"Tributary - Secondary Stream\"),\n    Lake            UMETA(DisplayName = \"Lake - Standing Water\"),\n    Wetland         UMETA(DisplayName = \"Wetland - Swamp Area\"),\n    SeasonalStream  UMETA(DisplayName = \"Seasonal Stream - Dry in Desert\"),\n    SpringSource    UMETA(DisplayName = \"Spring Source - Mountain Origin\")\n};\n\n/** Performance-optimized biome generation settings */\nUSTRUCT(BlueprintType)\nstruct FBiomeGenerationSettingsV3\n{\n    GENERATED_BODY()\n\n    /** Biome identifier */\n    UPROPERTY(EditAnywhere, BlueprintReadWrite, Category = \"Biome\")\n    EJurassicBiomeV3 BiomeType = EJurassicBiomeV3::Forest;\n\n    /** Elevation range for this biome (in cm) */\n    UPROPERTY(EditAnywhere, BlueprintReadWrite, Category = \"Terrain\", meta = (ClampMin = \"0\", ClampMax = \"300000\"))\n    FVector2D ElevationRange = FVector2D(0.0f, 50000.0f);\n\n    /** Slope angle range (in degrees) */\n    UPROPERTY(EditAnywhere, BlueprintReadWrite, Category = \"Terrain\", meta = (ClampMin = \"0\", ClampMax = \"90\"))\n    FVector2D SlopeRange = FVector2D(0.0f, 30.0f);\n\n    /** Distance from water sources (in cm) */\n    UPROPERTY(EditAnywhere, BlueprintReadWrite, Category = \"Water\")\n    FVector2D WaterDistanceRange = FVector2D(0.0f, 500000.0f);\n\n    /** Geological formation influence */\n    UPROPERTY(EditAnywhere, BlueprintReadWrite, Category = \"Geology\")\n    EGeologicalFormationV3 DominantFormation = EGeologicalFormationV3::Sedimentary;\n\n    /** Climate parameters */\n    UPROPERTY(EditAnywhere, BlueprintReadWrite, Category = \"Climate\")\n    float Temperature = 25.0f; // Celsius\n\n    UPROPERTY(EditAnywhere, BlueprintReadWrite, Category = \"Climate\")\n    float Humidity = 0.6f; // 0-1 range\n\n    UPROPERTY(EditAnywhere, BlueprintReadWrite, Category = \"Climate\")\n    float WindStrength = 0.3f; // 0-1 range\n\n    UPROPERTY(EditAnywhere, BlueprintReadWrite, Category = \"Climate\")\n    float Rainfall = 1200.0f; // mm per year\n\n    /** Noise parameters for terrain generation */\n    UPROPERTY(EditAnywhere, BlueprintReadWrite, Category = \"Noise\")\n    float PrimaryNoiseFreq = 0.0005f;\n\n    UPROPERTY(EditAnywhere, BlueprintReadWrite, Category = \"Noise\")\n    float SecondaryNoiseFreq = 0.002f;\n\n    UPROPERTY(EditAnywhere, BlueprintReadWrite, Category = \"Noise\")\n    float DetailNoiseFreq = 0.01f;\n\n    UPROPERTY(EditAnywhere, BlueprintReadWrite, Category = \"Noise\")\n    int32 NoiseOctaves = 6;\n\n    /** Transition zone settings */\n    UPROPERTY(EditAnywhere, BlueprintReadWrite, Category = \"Transitions\")\n    float TransitionWidth = 200000.0f; // 2km transition zones\n\n    UPROPERTY(EditAnywhere, BlueprintReadWrite, Category = \"Transitions\")\n    float BlendSmoothness = 0.7f;\n\n    /** Performance settings per biome */\n    UPROPERTY(EditAnywhere, BlueprintReadWrite, Category = \"Performance\")\n    int32 PCGGridSize = 12800; // cm, for hierarchical generation\n\n    UPROPERTY(EditAnywhere, BlueprintReadWrite, Category = \"Performance\")\n    float StreamingDistance = 500000.0f; // 5km streaming distance\n\n    UPROPERTY(EditAnywhere, BlueprintReadWrite, Category = \"Performance\")\n    int32 MaxVegetationInstances = 10000; // Per grid cell\n\n    UPROPERTY(EditAnywhere, BlueprintReadWrite, Category = \"Performance\")\n    float LODDistanceMultiplier = 1.0f; // Biome-specific LOD scaling\n\n    /** PCG Graphs for this biome */\n    UPROPERTY(EditAnywhere, BlueprintReadWrite, Category = \"PCG\")\n    TSoftObjectPtr<UPCGGraph> TerrainGraph;\n\n    UPROPERTY(EditAnywhere, BlueprintReadWrite, Category = \"PCG\")\n    TSoftObjectPtr<UPCGGraph> VegetationGraph;\n\n    UPROPERTY(EditAnywhere, BlueprintReadWrite, Category = \"PCG\")\n    TSoftObjectPtr<UPCGGraph> WaterGraph;\n\n    UPROPERTY(EditAnywhere, BlueprintReadWrite, Category = \"PCG\")\n    TSoftObjectPtr<UPCGGraph> DetailGraph;\n};\n\n/** World generation configuration V3 */\nUSTRUCT(BlueprintType)\nstruct FWorldGenerationConfigV3\n{\n    GENERATED_BODY()\n\n    /** World size settings - optimized for UE5 */\n    UPROPERTY(EditAnywhere, BlueprintReadWrite, Category = \"World Size\")\n    int32 LandscapeSize = 8129; // 8129x8129 for optimal performance\n\n    UPROPERTY(EditAnywhere, BlueprintReadWrite, Category = \"World Size\")\n    float WorldScale = 2500.0f; // 25m per landscape unit = ~200km²\n\n    UPROPERTY(EditAnywhere, BlueprintReadWrite, Category = \"World Size\")\n    float MaxElevation = 300000.0f; // 3km mountain peaks\n\n    /** Mountain border (impassable boundaries) */\n    UPROPERTY(EditAnywhere, BlueprintReadWrite, Category = \"Mountain Border\")\n    float BorderWidth = 1000000.0f; // 10km impassable border\n\n    UPROPERTY(EditAnywhere, BlueprintReadWrite, Category = \"Mountain Border\")\n    float BorderHeight = 250000.0f; // 2.5km high mountains\n\n    UPROPERTY(EditAnywhere, BlueprintReadWrite, Category = \"Mountain Border\")\n    float BorderSteepness = 0.9f; // Very steep, impassable\n\n    /** River system configuration */\n    UPROPERTY(EditAnywhere, BlueprintReadWrite, Category = \"River System\")\n    int32 MainRiverCount = 4; // Major rivers from mountains\n\n    UPROPERTY(EditAnywhere, BlueprintReadWrite, Category = \"River System\")\n    int32 TributaryCount = 12; // Secondary rivers\n\n    UPROPERTY(EditAnywhere, BlueprintReadWrite, Category = \"River System\")\n    float RiverWidth = 5000.0f; // 50m wide rivers\n\n    UPROPERTY(EditAnywhere, BlueprintReadWrite, Category = \"River System\")\n    float RiverDepth = 500.0f; // 5m deep rivers\n\n    /** Lake generation */\n    UPROPERTY(EditAnywhere, BlueprintReadWrite, Category = \"Lakes\")\n    int32 LakeCount = 8;\n\n    UPROPERTY(EditAnywhere, BlueprintReadWrite, Category = \"Lakes\")\n    FVector2D LakeSizeRange = FVector2D(50000.0f, 200000.0f); // 0.5-2km diameter\n\n    /** Player spawn location (Forest biome center) */\n    UPROPERTY(EditAnywhere, BlueprintReadWrite, Category = \"Player Spawn\")\n    FVector PlayerSpawnLocation = FVector(0.0f, 0.0f, 10000.0f); // 100m above forest center\n\n    /** Performance optimization settings */\n    UPROPERTY(EditAnywhere, BlueprintReadWrite, Category = \"Performance\")\n    EPerformanceTarget TargetPlatform = EPerformanceTarget::PC_HighEnd;\n\n    UPROPERTY(EditAnywhere, BlueprintReadWrite, Category = \"Performance\")\n    bool bUseWorldPartition = true;\n\n    UPROPERTY(EditAnywhere, BlueprintReadWrite, Category = \"Performance\")\n    bool bUseHierarchicalGeneration = true;\n\n    UPROPERTY(EditAnywhere, BlueprintReadWrite, Category = \"Performance\")\n    int32 WorldPartitionCellSize = 128000; // 1.28km cells\n\n    UPROPERTY(EditAnywhere, BlueprintReadWrite, Category = \"Performance\")\n    float StreamingRange = 640000.0f; // 6.4km streaming range\n\n    UPROPERTY(EditAnywhere, BlueprintReadWrite, Category = \"Performance\")\n    float GenerationBudgetMs = 2.0f; // Max 2ms per frame for generation\n\n    /** Biome distribution settings */\n    UPROPERTY(EditAnywhere, BlueprintReadWrite, Category = \"Biome Distribution\")\n    float ForestCenterRadius = 2000000.0f; // 20km forest in center\n\n    UPROPERTY(EditAnywhere, BlueprintReadWrite, Category = \"Biome Distribution\")\n    float BiomeTransitionSmoothness = 0.7f;\n\n    UPROPERTY(EditAnywhere, BlueprintReadWrite, Category = \"Biome Distribution\")\n    TMap<EJurassicBiomeV3, float> BiomeWeights;\n\n    /** Generation seed for reproducible worlds */\n    UPROPERTY(EditAnywhere, BlueprintReadWrite, Category = \"Generation\")\n    int32 WorldSeed = 12345;\n\n    /** Debug settings */\n    UPROPERTY(EditAnywhere, BlueprintReadWrite, Category = \"Debug\")\n    bool bShowBiomeDebugColors = false;\n\n    UPROPERTY(EditAnywhere, BlueprintReadWrite, Category = \"Debug\")\n    bool bShowRiverDebugLines = false;\n\n    UPROPERTY(EditAnywhere, BlueprintReadWrite, Category = \"Debug\")\n    bool bShowPerformanceStats = true;\n\n    FWorldGenerationConfigV3()\n    {\n        // Initialize default biome weights\n        BiomeWeights.Add(EJurassicBiomeV3::Forest, 0.3f);\n        BiomeWeights.Add(EJurassicBiomeV3::Swamp, 0.2f);\n        BiomeWeights.Add(EJurassicBiomeV3::Savana, 0.2f);\n        BiomeWeights.Add(EJurassicBiomeV3::Desert, 0.15f);\n        BiomeWeights.Add(EJurassicBiomeV3::SnowyRockside, 0.1f);\n        BiomeWeights.Add(EJurassicBiomeV3::RiverPlains, 0.05f);\n    }\n};\n\n/** Performance monitoring for world generation */\nUSTRUCT(BlueprintType)\nstruct FWorldGenPerformanceStats\n{\n    GENERATED_BODY()\n\n    UPROPERTY(BlueprintReadOnly, Category = \"Performance\")\n    float TerrainGenerationTime = 0.0f;\n\n    UPROPERTY(BlueprintReadOnly, Category = \"Performance\")\n    float BiomeGenerationTime = 0.0f;\n\n    UPROPERTY(BlueprintReadOnly, Category = \"Performance\")\n    float RiverGenerationTime = 0.0f;\n\n    UPROPERTY(BlueprintReadOnly, Category = \"Performance\")\n    float VegetationGenerationTime = 0.0f;\n\n    UPROPERTY(BlueprintReadOnly, Category = \"Performance\")\n    float TotalGenerationTime = 0.0f;\n\n    UPROPERTY(BlueprintReadOnly, Category = \"Performance\")\n    int32 ActivePCGComponents = 0;\n\n    UPROPERTY(BlueprintReadOnly, Category = \"Performance\")\n    int32 StreamingCellsLoaded = 0;\n\n    UPROPERTY(BlueprintReadOnly, Category = \"Performance\")\n    float MemoryUsageMB = 0.0f;\n\n    UPROPERTY(BlueprintReadOnly, Category = \"Performance\")\n    bool bWithinPerformanceBudget = true;\n};\n\n/**\n * @brief Advanced Jurassic World Generator V3\n * \n * Performance-optimized world generation system that creates the prehistoric\n * survival world according to the game concept. Integrates with Agent #4's\n * performance optimization framework to maintain 60fps PC / 30fps console.\n * \n * Key Features:\n * - Geological simulation for realistic terrain\n * - Climate-based biome distribution\n * - Hydrological river system modeling\n * - Performance-first PCG implementation\n * - World Partition integration\n * - Real-time performance monitoring\n */\nUCLASS(BlueprintType, Blueprintable)\nclass TRANSPERSONALGAME_API AJurassicWorldGeneratorV3 : public AActor\n{\n    GENERATED_BODY()\n\npublic:\n    AJurassicWorldGeneratorV3();\n\nprotected:\n    virtual void BeginPlay() override;\n    virtual void OnConstruction(const FTransform& Transform) override;\n    virtual void Tick(float DeltaTime) override;\n\n    /** Main PCG component for world orchestration */\n    UPROPERTY(VisibleAnywhere, BlueprintReadOnly, Category = \"PCG\")\n    TObjectPtr<UPCGComponent> MainPCGComponent;\n\n    /** Terrain generation PCG component */\n    UPROPERTY(VisibleAnywhere, BlueprintReadOnly, Category = \"PCG\")\n    TObjectPtr<UPCGComponent> TerrainPCGComponent;\n\n    /** Biome distribution PCG component */\n    UPROPERTY(VisibleAnywhere, BlueprintReadOnly, Category = \"PCG\")\n    TObjectPtr<UPCGComponent> BiomePCGComponent;\n\n    /** River system PCG component */\n    UPROPERTY(VisibleAnywhere, BlueprintReadOnly, Category = \"PCG\")\n    TObjectPtr<UPCGComponent> RiverPCGComponent;\n\n    /** Vegetation PCG component */\n    UPROPERTY(VisibleAnywhere, BlueprintReadOnly, Category = \"PCG\")\n    TObjectPtr<UPCGComponent> VegetationPCGComponent;\n\n    /** World generation configuration */\n    UPROPERTY(EditAnywhere, BlueprintReadWrite, Category = \"World Configuration\")\n    FWorldGenerationConfigV3 WorldConfig;\n\n    /** Biome generation settings */\n    UPROPERTY(EditAnywhere, BlueprintReadWrite, Category = \"Biome Configuration\")\n    TMap<EJurassicBiomeV3, FBiomeGenerationSettingsV3> BiomeSettings;\n\n    /** Performance monitoring */\n    UPROPERTY(BlueprintReadOnly, Category = \"Performance\")\n    FWorldGenPerformanceStats PerformanceStats;\n\n    /** Reference to performance monitor from Agent #4 */\n    UPROPERTY()\n    TObjectPtr<UPerformanceMonitor> PerformanceMonitor;\n\npublic:\n    /** Generate the complete world */\n    UFUNCTION(BlueprintCallable, Category = \"World Generation\")\n    void GenerateWorld();\n\n    /** Generate specific biome area */\n    UFUNCTION(BlueprintCallable, Category = \"World Generation\")\n    void GenerateBiome(EJurassicBiomeV3 BiomeType, const FVector& Center, float Radius);\n\n    /** Generate river system */\n    UFUNCTION(BlueprintCallable, Category = \"World Generation\")\n    void GenerateRiverSystem();\n\n    /** Update performance statistics */\n    UFUNCTION(BlueprintCallable, Category = \"Performance\")\n    void UpdatePerformanceStats();\n\n    /** Get biome at world location */\n    UFUNCTION(BlueprintPure, Category = \"World Query\")\n    EJurassicBiomeV3 GetBiomeAtLocation(const FVector& WorldLocation) const;\n\n    /** Get elevation at world location */\n    UFUNCTION(BlueprintPure, Category = \"World Query\")\n    float GetElevationAtLocation(const FVector& WorldLocation) const;\n\n    /** Get water distance at location */\n    UFUNCTION(BlueprintPure, Category = \"World Query\")\n    float GetWaterDistanceAtLocation(const FVector& WorldLocation) const;\n\n    /** Check if location is within performance budget */\n    UFUNCTION(BlueprintPure, Category = \"Performance\")\n    bool IsLocationWithinPerformanceBudget(const FVector& Location) const;\n\nprotected:\n    /** Internal generation functions */\n    void GenerateTerrain();\n    void GenerateBiomes();\n    void GenerateRivers();\n    void GenerateVegetation();\n    void SetupWorldPartition();\n    void InitializePerformanceMonitoring();\n\n    /** Geological simulation functions */\n    float CalculateGeologicalHeight(const FVector2D& Location, EGeologicalFormationV3 Formation) const;\n    float ApplyErosionSimulation(const FVector2D& Location, float BaseHeight) const;\n    float CalculateHydraulicErosion(const FVector2D& Location, float Height) const;\n    float CalculateThermalErosion(const FVector2D& Location, float Height) const;\n\n    /** Climate simulation functions */\n    float CalculateTemperature(const FVector2D& Location, float Elevation) const;\n    float CalculateHumidity(const FVector2D& Location, float WaterDistance) const;\n    float CalculateRainfall(const FVector2D& Location, float Temperature, float Humidity) const;\n\n    /** Biome determination functions */\n    EJurassicBiomeV3 DetermineBiome(const FVector2D& Location, float Elevation, float Temperature, float Humidity) const;\n    float CalculateBiomeWeight(const FVector2D& Location, EJurassicBiomeV3 BiomeType) const;\n    float CalculateTransitionBlend(const FVector2D& Location, EJurassicBiomeV3 FromBiome, EJurassicBiomeV3 ToBiome) const;\n\n    /** River system functions */\n    TArray<FVector> GenerateRiverPath(const FVector& Start, const FVector& End) const;\n    void CarveRiverChannel(const TArray<FVector>& RiverPath, float Width, float Depth);\n    TArray<FVector> FindWaterSources() const;\n    TArray<FVector> FindRiverMouths() const;\n\n    /** Performance optimization functions */\n    void OptimizePCGGeneration();\n    void AdjustLODDistances();\n    void ManageStreamingCells();\n    bool CheckPerformanceBudget() const;\n\n    /** Utility functions */\n    FVector2D WorldToLandscapeCoords(const FVector& WorldLocation) const;\n    FVector LandscapeToWorldCoords(const FVector2D& LandscapeCoords) const;\n    float SampleNoiseAtLocation(const FVector2D& Location, float Frequency, int32 Octaves) const;\n    float GetLandscapeHeightAtLocation(const FVector2D& Location) const;\n\n    /** Debug visualization */\n    void DrawBiomeDebugColors();\n    void DrawRiverDebugLines();\n    void DrawPerformanceDebugInfo();\n\nprivate:\n    /** Internal state */\n    bool bIsGenerating = false;\n    bool bWorldGenerated = false;\n    float LastPerformanceUpdate = 0.0f;\n    TArray<FVector> GeneratedRiverPaths;\n    TMap<EJurassicBiomeV3, TArray<FVector>> BiomeCenters;\n};\n"